number_charthaco_charsheet.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	DB.addHandler("options.HouseRule_ASCENDING_AC", "onUpdate", onOptionChanged);
	onOptionChanged();
end
function onClose()
	if super and super.onClose then
		super.onClose();
	end
	DB.removeHandler("options.HouseRule_ASCENDING_AC", "onUpdate", onOptionChanged);
end
function onOptionChanged()
	setVisible(not (AscendingACManager and AscendingACManager.isOn and AscendingACManager.isOn()));
end

