windowclass.script:
function onInit()
	DB.addHandler("options.HouseRule_ASCENDING_AC", "onUpdate", onOptionChanged);
	onOptionChanged();
end
function onClose()
	DB.removeHandler("options.HouseRule_ASCENDING_AC", "onUpdate", onOptionChanged);
end
function onOptionChanged()
	local bOn = AscendingACManager and AscendingACManager.isOn and AscendingACManager.isOn();
	combat_ascendingac_matrix.setVisible(bOn);
	if bOn then
		abilitynotes.setAnchor("top", "combat_ascendingac_matrix", "bottom", "relative", 10);
	else
		abilitynotes.setAnchor("top", "initiative", "bottom", "relative", 10);
	end
end

button_turnundead.script:
function onInit()
	DB.addHandler(DB.getPath(window.getDatabaseNode(), "turn.total"), "onUpdate", onValueChanged);
	onValueChanged();
end
function onClose()
	DB.removeHandler(DB.getPath(window.getDatabaseNode(), "turn.total"), "onUpdate", onValueChanged);
end
function onValueChanged()
	local nTLevel = DB.getValue(window.getDatabaseNode(), "turn.total", 0);
	local bShow = (nTLevel > 0);
	setVisible(bShow);
	window.label_turnlevel.setVisible(bShow);
end
